void bpnn_layerforward_ocl(float *input_cuda, float *output_hidden_cuda, float *input_hidden_cuda, float *hidden_partial_sum, int in, int hid)
{
  int by, tx, ty;
  int index, index_in;
  float input_node[HEIGHT];
  float weight_matrix[HEIGHT * WIDTH];

  int num_blocks = in / BLOCK_SIZE;

  #pragma omp parallel for private(by, tx, ty, index, index_in) shared(input_cuda, output_hidden_cuda, input_hidden_cuda, hidden_partial_sum, input_node, weight_matrix)
  for (by = 0; by < num_blocks; by++) {
    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        index_in = HEIGHT * by + ty + 1;

        if (tx == 0) {
          input_node[ty] = input_cuda[index_in];
        }

        weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];

        weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] * input_node[ty];

        for (int i = 1; i <= HEIGHT; i = i * 2) {
          int power_two = i;
          if (ty % power_two == 0 && (ty + power_two/2) < HEIGHT) {
            weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2) * WIDTH + tx];
          }
        }

        input_hidden_cuda[index] = weight_matrix[ty * WIDTH + tx];

        if (tx == 0) {
          hidden_partial_sum[by * hid + ty] = weight_matrix[0 * WIDTH + ty];
        }
      }
    }
  }
}

void bpnn_adjust_weights_ocl(float *delta, int hid, float *ly, int in, float *w, float *oldw)
{
  int by, tx, ty;
  int index, index_y, index_x;
  int num_blocks = in / BLOCK_SIZE;

  #pragma omp parallel for private(by, tx, ty, index, index_y, index_x) shared(delta, hid, ly, in, w, oldw)
  for (by = 0; by < num_blocks; by++) {
    for (ty = 0; ty < HEIGHT; ty++) {
      for (tx = 0; tx < WIDTH; tx++) {
        index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        index_y = HEIGHT * by + ty + 1;
        index_x = tx + 1;

        if (index <= (in + 1) * (hid + 1) && index_x <= hid + 1 && index_y <= in + 1) {
          float update = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
          w[index] += update;
          oldw[index] = update;
        }

        if (ty == 0 && by == 0 && index_x <= hid + 1) {
          float update = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
          w[index_x] += update;
          oldw[index_x] = update;
        }
      }
    }
  }
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;
  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  float *partial_sum;
  float sum;
  int num_blocks;
  int m, k, j;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  num_blocks = in / BLOCK_SIZE;

  input_weights_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

  m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
      m++;
    }
  }

  printf("Performing CPU computation\n");

  bpnn_layerforward_ocl(net->input_units, net->hidden_units, input_weights_one_dim, partial_sum, in, hid);

  for (j = 1; j <= hid; j++) {
    sum = 0.0;
    for (k = 0; k < num_blocks; k++) {
      sum += partial_sum[k * hid + j - 1];
    }
    sum += net->input_weights[0][j];
    net->hidden_units[j] = squash(sum);
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  bpnn_adjust_weights_ocl(net->hidden_delta, hid, net->input_units, in, input_weights_one_dim, input_weights_prev_one_dim);

  m = 0;
  for (k = 0; k <= in; k++) {
    for (j = 0; j <= hid; j++) {
      net->input_weights[k][j] = input_weights_one_dim[m];
      net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
      m++;
    }
  }

  free(input_weights_prev_one_dim);
  free(partial_sum);
  free(input_weights_one_dim);

  *eo = out_err;
  *eh = hid_err;

  return 0;
}

int layer_size = 0;
